/**
 * V3 Converter - Normalization Layer
 *
 * Transforms incoming V3 extraction payload into a lossless intermediate model
 * used by analyzer/segmenter/mapper. Preserves all fields for no-drop fallback handling.
 *
 * @fileType utility
 * @domain conversion
 * @pattern normalization
 */

import type {
  SubQuestionExtraction,
  MultiPartExtraction,
} from '@/server/services/exercise-conversion/v3/transform'

// ---------------------------------
// Normalized Types
// ---------------------------------

/**
 * V3 Converter - Table Parser
 *
 * Parses HTML and markdown tables into question_table block schema format.
 *
 * @fileType utility
 * @domain conversion
 * @pattern parsing
 */

// ---------------------------------
// Types
// ---------------------------------

export interface ParsedTable {
  headers: string[]
  rowsData: string[][]
  answers: Record<string, string>
}

/**
 * V3 Converter - Matching Parser
 *
 * Parses matching structures into question_matching block schema format.
 *
 * @fileType utility
 * @domain conversion
 * @pattern parsing
 */

import { nanoid } from 'nanoid'

// ---------------------------------
// Types
// ---------------------------------

export interface MatchingOption {
  id: string
  content: string
}

export const QuestionFreeResponseBlockSchema = z
  .object({
    id: z.string().min(1),
    type: z.literal('question_free_response'),
    prompt: InlineRichTextSchema,
    answer: FreeResponseAnswerSchema,

    hint: InlineRichTextSchema.optional(),
    solution: InlineRichTextSchema.optional(),
    fullSolution: InlineRichTextSchema.optional(),
  })
  .strict()

// ---------------------------------
// Zod: Latex Block
// ---------------------------------
export const LatexBlockSchema = z
  .object({
    id: z.string().min(1),

          message: `correctPairs contains unknown matchId: ${pair.matchId}`,
          path: ['correctPairs'],
        })
      }
    }
  })

// ---------------------------------
// Zod: SVG Hotspot Schema
// ---------------------------------
const SvgHotspotSchema = z
  .object({
    id: z.string().min(1),
    selector: z.string().min(1),
    label: z.string().optional(),
  })
  .strict()

// ---------------------------------
// Zod: SVG Block Schema

      .refine(
        (html) => validateHtmlTags(html),
        'HTML contains disallowed tags. Only safe formatting tags are permitted.',
      )
      .refine(
        (html) => !DANGEROUS_HTML_PATTERNS.some((pattern) => pattern.test(html)),
        'HTML contains blocked content (event handlers, javascript:, vbscript:, or data: URLs)',
      ),
  })
  .strict()

// ---------------------------------
// Zod: Media Block (reference to a single media item)
// ---------------------------------
export const MediaBlockSchema = z
  .object({
    id: z.string().min(1),
    type: z.literal('media'),
    mediaId: z.string().min(1),
  })
